const express = require('express');
const bodyParser = require('body-parser');
const path = require('path');
const fs = require('fs').promises;
const { renderBlockSelector } = require('./logic/generators/renderBlockSelector');
const { renderArticle } = require('./logic/renderers/articleRenderer');
const { renderProperties } = require('./logic/utilities/formRenderUtils'); 
const _ = require('lodash');

const app = express();
const PORT = 3000; 

// Middleware
app.use(bodyParser.urlencoded({ extended: true, limit: '50mb' }));
app.use(bodyParser.json({ limit: '50mb' }));
app.use(express.static('public')); 
app.set('view engine', 'ejs');
app.set('views', path.join(__dirname, 'views'));

// Helper: Load JSON
const loadJson = async (filePath) => {
    try {
        const absolutePath = path.resolve(filePath);
        const data = await fs.readFile(absolutePath, 'utf8');
        return JSON.parse(data);
    } catch (err) {
        console.error(`[LOAD ERROR] ${filePath}: ${err.message}`);
        throw err;
    }
};

/**
 * NEW HELPER: Reads content directory to get list of existing page slugs.
 */
const getExistingSlugs = async () => {
    try {
        const files = await fs.readdir(path.join(__dirname, 'content', 'live'));
        return files.filter(file => file.endsWith('.json')).map(file => file.replace('.json', ''));
    } catch (e) {
        console.error("Error reading content directory:", e);
        return []; 
    }
};

const getBlockDefinition = (fullSchema, type) => {
    return fullSchema.properties.contentBlocks.items.oneOf
        .find(def => def.properties.type.const === type);
};

// Stage 2: Generates the final, long static form.
const renderStaticContentForm = (schema, blockOrder, initialData = {}) => {
    let formHtml = '';

    // 1. Prepare initial data fields
    const topLevelProps = {
        slug: schema.properties.slug,
        status: schema.properties.status,
        metadata: schema.properties.metadata
    };
    
    // We pass the full initialData object to renderProperties for pre-population
    const initialValues = {
        slug: initialData.slug,
        status: initialData.status,
        metadata: initialData.metadata || { title: '', description: '', canonicalUrl: '', ogImage: '' } 
    };
    
    // 1. Render Top Level Meta Fields
    formHtml += '<div class="card-panel" style="margin-bottom: 30px;"><h2>Article Settings</h2><div class="row">';
    formHtml += renderProperties(topLevelProps, initialValues);
    formHtml += '</div></div>';


    // 2. Render Content Blocks Sequentially
    formHtml += '<h2>Content Blocks</h2>';
    
    blockOrder.forEach((type, index) => {
        const blockDef = getBlockDefinition(schema, type);
        if (!blockDef) return; 

        const blockTitle = blockDef.title || type;
        const blockFields = blockDef.properties.data.properties;
        
        // **DEFENSIVE FIX**: Ensure block exists before accessing .data, otherwise use an empty object
        const savedBlock = initialData.contentBlocks ? initialData.contentBlocks[index] : null;
        const blockData = savedBlock && savedBlock.data ? savedBlock.data : {};
        
        const prefix = `blocks[${index}]`;

        // The input fields for the content block (data properties)
        let blockHtml = `<input type="hidden" name="blocks[${index}][type]" value="${type}" />`;
        
        // Render fields using the utility function, passing the specific saved block data
        blockHtml += renderProperties(blockFields, blockData, prefix + '[data]');

        // Wrap each block
        formHtml += `
            <div class="card hoverable block-item" data-type="${type}" style="margin-bottom: 20px;">
                <div class="card-content">
                    <span class="card-title" style="font-size: 1.2rem; font-weight: bold;">
                        Position ${index + 1}: ${blockTitle}
                    </span>
                    <div class="row">
                        ${blockHtml}
                    </div>
                </div>
            </div>
        `;
    });

    // 3. Final Form Wrapper
    return `
        <form id="cms-static-form" method="POST" action="/admin/save">
            ${formHtml}
            <button type="submit" class="btn-large waves-effect waves-light green darken-3" style="margin-top: 30px;">
                <i class="material-icons left">save</i> Save Final Content
            </button>
        </form>
        <script>
            document.addEventListener('DOMContentLoaded', function() {
                M.FormSelect.init(document.querySelectorAll('select'));
                M.updateTextFields();
            });
        </script>
    `;
};


// --- ROUTES ---

// 0. ROOT -> Homepage
app.get('/', (req, res) => res.redirect('/homepage'));

// 1. Admin: STAGE 1 (New/Edit Selector)
app.get('/admin/new', async (req, res, next) => {
    try {
        const schema = await loadJson('./logic/schemas/article.schema.json');
        const existingSlugs = await getExistingSlugs(); 
        const errorMessage = req.query.error; 

        const formHtml = renderBlockSelector(schema, existingSlugs, errorMessage); 

        // Check if an Edit request came from the slug selector dropdown
        const editSlug = req.query.slugExisting;
        if (editSlug) {
             // If editing, we skip the selector and load content for stage 2 immediately
             
             // Get block types from saved content
             const contentPath = `./content/live/${editSlug}.json`;
             const savedData = await loadJson(contentPath);
             
             // Build the blockOrder string from the existing content
             const blockOrder = savedData.contentBlocks.map(b => b.type).join(', ');
             
             // Now, redirect internally to Stage 2 with all parameters
             return res.redirect(`/admin/stage-2?slugMode=edit&slugExisting=${editSlug}&status=${savedData.status}&blockOrder=${blockOrder}`);

        }
        
        res.render('admin', { formHtml });
    } catch (err) { console.error(err); next(err); }
});

// 2. Admin: STAGE 2 (Static Form Renderer + Validation)
app.get('/admin/stage-2', async (req, res, next) => {
    try {
        const { slugMode, slugNew, slugExisting, status, blockOrder } = req.query;
        let targetSlug = '';
        const existingSlugs = await getExistingSlugs(); 

        // Determine the target slug based on mode
        if (slugMode === 'new') {
            targetSlug = slugNew.trim().toLowerCase();
            
            // **VALIDATION CHECK 1: Duplication**
            if (existingSlugs.includes(targetSlug)) {
                return res.redirect(`/admin/new?error=Slug%20'${targetSlug}'%20already%20exists!%20Please%20choose%20Edit%20Existing%20or%20a%20different%20name.`);
            }
        } else if (slugMode === 'edit') {
            targetSlug = slugExisting;
        } else {
            // Error handling for empty slug not needed if Stage 1 required fields
            targetSlug = 'untitled'; 
        }

        const blockTypes = blockOrder.split(',').map(s => s.trim()).filter(s => s.length > 0);
        const schema = await loadJson('./logic/schemas/article.schema.json');
        
        // Data object to carry initial setup data
        const initialData = { slug: targetSlug, status: status, metadata: {} };

        // **EDIT MODE**: Attempt to load existing content if editing
        if (slugMode === 'edit') {
            try {
                const contentPath = `./content/live/${targetSlug}.json`;
                const savedData = await loadJson(contentPath);
                
                // If editing, we use the saved content's metadata and contentBlocks
                initialData.metadata = savedData.metadata;
                initialData.contentBlocks = savedData.contentBlocks;
            } catch (e) {
                 // Log error but proceed to render an empty form based on the blockOrder
                 console.error(`[EDIT ERROR] File for ${targetSlug} not found during Stage 2 load. Rendering empty form.`);
            }
        }

        // Pass the static form to the Admin view
        const formHtml = renderStaticContentForm(schema, blockTypes, initialData); 
        
        res.render('admin', { formHtml });

    } catch (err) { console.error(err); next(err); }
});

// 3. Public: View Article (Stays the same)
app.get('/:slug', async (req, res, next) => {
    try {
        const slug = req.params.slug;
        const contentPath = `./content/live/${slug}.json`;
        
        try { await fs.access(contentPath); } 
        catch { return next(); } 

        const [article, globalConfig] = await Promise.all([
            loadJson(contentPath),
            loadJson('./system/global.json')
        ]);

        const viewData = {
            metadata: article.metadata,
            header: globalConfig.site, 
            footer: globalConfig.footer,
            contentBlocks: article.contentBlocks || [] 
        };

        res.render('index', { data: viewData });

    } catch (err) {
        console.error("RENDER CRASH:", err);
        next(err);
    }
});

// 4. Admin: Save Content (Stays the same)
app.post('/admin/save', async (req, res) => {
    try {
        const formData = req.body;
        
        const blockDataArray = [];
        if (formData.blocks) {
            for (const key in formData.blocks) {
                const block = formData.blocks[key];
                blockDataArray.push({
                    type: block.type, 
                    data: block.data
                });
            }
        }
        
        const articleData = {
            slug: formData.slug || 'untitled',
            status: formData.status,
            metadata: {
                title: formData.metadata.title,
                description: formData.metadata.description,
                canonicalUrl: formData.metadata.canonicalUrl
            },
            contentBlocks: blockDataArray
        };

        const fileName = `${articleData.slug}.json`;
        await fs.writeFile(`./content/live/${fileName}`, JSON.stringify(articleData, null, 2));
        res.send(`<h1>Saved!</h1><a href="/${articleData.slug}">View Page</a>`);
    } catch (err) {
        console.error(err);
        res.status(500).send("Save Error: " + err.message);
    }
});

// Start
app.listen(PORT, () => {
    console.log(`\n--- Server Running on Port ${PORT} ---`);
    console.log(`View Site:  http://localhost:${PORT}`);
    console.log(`Admin Tool: http://localhost:${PORT}/admin/new\n`);
});
EOF
